setup_steps.sql:
CREATE USER 'fluig_user'@'%' IDENTIFIED BY 'sua_senha';
GRANT ALL PRIVILEGES ON fluig_db.* TO 'fluig_user'@'%';
FLUSH PRIVILEGES;

CREATE TABLESPACE fluig_tbs DATAFILE 'fluig_tbs.dbf' SIZE 5G AUTOEXTEND ON;
CREATE USER fluig_user IDENTIFIED BY sua_senha DEFAULT TABLESPACE fluig_tbs;
GRANT CONNECT, RESOURCE TO fluig_user;
GRANT UNLIMITED TABLESPACE TO fluig_user;

CREATE LOGIN fluig_login WITH PASSWORD = 'Sua_Senha123!';
USE fluig_db;
CREATE USER fluig_user FOR LOGIN fluig_login;
ALTER ROLE db_owner ADD MEMBER fluig_user;
